import React from "react";
import "./Card_style.css";
const Card = () => {
            return (
           <>
           <div className="card_container">
               <div className="card_img__box">
                        <img src="" alt="" className="card_img" />
               </div>
               <div className="card_heading">
                             <span className="card_heading__text">Title</span>
               </div>
               <div className="card_content">
                                        <p>Lorem ipsum dolor sit amet consectetur adipisicing elit. Quisquam, quibusdam.</p>        
               </div>
               <div className="card_more">
                                       <button className="like_btn"></button>
                                       <span className="like_count"></span>
                                       
               </div>
           </div>
           
           </>
            );
            }
export default Card;
